package com.kalyani.car_rental_backend.driver.entity;
import com.kalyani.car_rental_backend.user.entity.User;import jakarta.persistence.*;import java.math.BigDecimal;import java.time.LocalDateTime;
@Entity@Table(name="driver_profiles",uniqueConstraints=@UniqueConstraint(name="uk_driver_user",columnNames="user_id"))public class DriverProfile{@Id@GeneratedValue(strategy=GenerationType.IDENTITY)private Long id;@OneToOne(optional=false)private User user;@Column(nullable=false)private String verificationStatus="PENDING";@Column(nullable=false)private boolean online;private String licenseNumber;private String aadhaarLast4;private String vehicleNumber;private String vehicleModel;private Double currentLatitude;private Double currentLongitude;private BigDecimal walletBalance=BigDecimal.ZERO;private BigDecimal totalEarnings=BigDecimal.ZERO;private Double averageRating=0.0;private Integer completedTrips=0;private LocalDateTime updatedAt;@PrePersist@PreUpdate void pre(){updatedAt=LocalDateTime.now();if(walletBalance==null)walletBalance=BigDecimal.ZERO;if(totalEarnings==null)totalEarnings=BigDecimal.ZERO;if(averageRating==null)averageRating=0.0;if(completedTrips==null)completedTrips=0;}
public Long getId(){return id;}public User getUser(){return user;}public void setUser(User v){user=v;}public String getVerificationStatus(){return verificationStatus;}public void setVerificationStatus(String v){verificationStatus=v;}public boolean isOnline(){return online;}public void setOnline(boolean v){online=v;}public String getLicenseNumber(){return licenseNumber;}public void setLicenseNumber(String v){licenseNumber=v;}public String getAadhaarLast4(){return aadhaarLast4;}public void setAadhaarLast4(String v){aadhaarLast4=v;}public String getVehicleNumber(){return vehicleNumber;}public void setVehicleNumber(String v){vehicleNumber=v;}public String getVehicleModel(){return vehicleModel;}public void setVehicleModel(String v){vehicleModel=v;}public Double getCurrentLatitude(){return currentLatitude;}public void setCurrentLatitude(Double v){currentLatitude=v;}public Double getCurrentLongitude(){return currentLongitude;}public void setCurrentLongitude(Double v){currentLongitude=v;}public BigDecimal getWalletBalance(){return walletBalance;}public void setWalletBalance(BigDecimal v){walletBalance=v;}public BigDecimal getTotalEarnings(){return totalEarnings;}public void setTotalEarnings(BigDecimal v){totalEarnings=v;}public Double getAverageRating(){return averageRating;}public void setAverageRating(Double v){averageRating=v;}public Integer getCompletedTrips(){return completedTrips;}public void setCompletedTrips(Integer v){completedTrips=v;}public LocalDateTime getUpdatedAt(){return updatedAt;}}
